class SORTracker {
public:
    set<pair<int, string>> locations;
    int query_count = 0;

    SORTracker() {

    }

    void add(string name, int score) {
        locations.insert({-score, name});
    }

    string get() {
        query_count++;
        auto it = locations.begin();
        for (int i = 0; i < query_count - 1; i++) {
            it++;
        }
        return it->second;
    }
};

